echo '#!/bin/sh' > hola.sh #It creates a file named hola.sh and writes #!/bin/sh into it, which defines the script interpreter
echo 'echo "Hola desde mi primer script"' >> hola.sh #It appends the line echo "Hola desde mi primer script" to hola.sh without overwriting the existing content.
cat hola.sh #It displays the content of the file hola.sh on the screen